insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('educacao', 'educacao', 'Educação & Futuro', 'Ferramentas para transformar conhecimento em oportunidade. Apostilas para o ENEM, guias de carreira, finanças pessoais e currículo — tudo para abrir portas.', '🎓', '#065F46', '#D1FAE5', 'eyebrow-green', 'cat-label-edu', 0, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('literatura', 'literatura', 'Tesouros da Literatura', 'Os maiores clássicos da literatura brasileira e mundial em domínio público. Patrimônio cultural de toda a humanidade, agora acessível para todos.', '📚', '#1e40af', '#DBEAFE', 'eyebrow-navy', 'cat-label-lit', 1, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('ciencia', 'ciencia', 'Ciência e Tecnologia', 'Descobertas científicas, inovações tecnológicas e conhecimento que moldam o futuro. De biologia a física quântica, explore os mistérios do universo.', '🔬', '#1e40af', '#DBEAFE', 'eyebrow-blue', 'cat-label-ciencia', 2, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('historia', 'historia', 'História', 'Jornadas através do tempo que revelam as origens da humanidade. De civilizações antigas às guerras mundiais, compreenda como chegamos até aqui.', '🏛️', '#92400e', '#FEF3C7', 'eyebrow-brown', 'cat-label-historia', 3, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('sociais', 'sociais', 'Ciências Sociais', 'Estudos sobre sociedade, comportamento humano e instituições. Sociologia, economia, direito e antropologia para entender como funcionam as comunidades.', '👥', '#374151', '#F3F4F6', 'eyebrow-gray', 'cat-label-sociais', 4, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('arte', 'arte', 'Arte e Cultura', 'Expressões artísticas e manifestações culturais que enriquecem a alma humana. Pintura, música, teatro e tradições que conectam passado e presente.', '🎨', '#be185d', '#fce7f3', 'eyebrow-pink', 'cat-label-arte', 5, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('religiao', 'religiao', 'Religião', 'Textos sagrados, estudos teológicos e reflexões espirituais. Uma jornada de fé, ética e compreensão do divino através das grandes tradições religiosas.', '🙏', '#3730a3', '#e0e7ff', 'eyebrow-indigo', 'cat-label-religiao', 6, true);
insert into public.categorias (id, route, label, description, emoji, color, bg_color, eyebrow_class, badge_class, sort_order, is_active) values ('filosofia', 'filosofia', 'Filosofia & Pensamento', 'Obras que provocam reflexão, questionamento e expansão da mente. De clássicos da filosofia a ensaios contemporâneos sobre ética, política e existência.', '🧠', '#6D28D9', '#EDE9FE', 'eyebrow-purple', 'cat-label-fil', 7, true);
